        }

        // Change the OverlapCircle to use transform.position (world space) instead of localPosition
        Collider2D collider2 = Physics2D.OverlapCircle(transform.position + move, 0.5f, LayerMask.GetMask("Food"));
        if (collider2 != null && collider2.CompareTag("Food"))
        {
            // Make sure the food object is part of the current TrainingArea
